def write_verse(n: int):
    data = VERSES[n]
    verse = {
        "id": f"BG 6.{n}",
        "chapter": 6,
        "verse": n,
        "schema_version": "1.0.0",
        "eval_suite_version": "1.0.0",
        "engineering": {
            "translation": data["translation"],
            "concrete_scenario": data["concrete_scenario"],
            "falsifiability": data["falsifiability"],
            "counter_example": data["counter_example"],
            "implication": data["implication"],
            "quotable_line": data["quotable_line"],
            "tags": data["tags"],
            "confidence": data["confidence"],
            "stretched": data["stretched"],
            "out_of_scope": False
        },
        "iterations": [{
            "iteration": 0,
            "ts": NOW,
            "mutation": data["iter_note"],
            "failing_gates_before": [],
            "failing_gates_after": [],
            "prompt_version": "draft-1.0.0"
        }],
        "gate_results": [],
        "total_score": 0,
        "max_score": 84,
        "needs_human_rescue": False
    }
    out = VRS / f"bg-6-{n}.json"
    out.write_text(json.dumps(verse, indent=2, ensure_ascii=False))
    print(f"  wrote bg-6-{n}.json")


def main():
    print("Patching source packs 6.25-6.30 (anvaya, literal, consensus, disagreements):")
